function encrypt(plaintext: string): string {
  if (!plaintext) return plaintext

  const key = getMasterKey()
  const iv = randomBytes(IV_LENGTH)
  const cipher = createCipheriv(ALGORITHM, key, iv)

  const encrypted = Buffer.concat([
    cipher.update(plaintext, "utf8"),
    cipher.final(),
  ])
  const authTag = cipher.getAuthTag()

  // Format: base64(iv + authTag + ciphertext)
  return Buffer.concat([iv, authTag, encrypted]).toString("base64")
}

function decryptWithPrefix(value: string): string {
  if (!value || !isEncrypted(value)) return value
  return decrypt(value.slice(PREFIX.length))
}

function encryptFields<T extends Record<string, unknown>>(
  obj: T,
  fields: (keyof T)[]
): T {
  const result = { ...obj }
  for (const field of fields) {
    if (result[field] && typeof result[field] === "string") {
      result[field] = encrypt(result[field] as string) as T[keyof T]
    }
  }
  return result
}

function decryptFields<T extends Record<string, unknown>>(
  obj: T,
  fields: (keyof T)[]
): T {
  const result = { ...obj }
  for (const field of fields) {
    if (result[field] && typeof result[field] === "string") {
      result[field] = decrypt(result[field] as string) as T[keyof T]
    }
  }
  return result
}

function encryptWithPrefix(plaintext: string): string {
  if (!plaintext) return plaintext
  return PREFIX + encrypt(plaintext)
}

function isEncrypted(value: string): boolean {
  return typeof value === "string" && value.startsWith(PREFIX)
}

function decryptTripPII(trip: Trip): Trip {
  return {
    ...trip,
    rawText: trip.rawText ? decryptWithPrefix(trip.rawText) : trip.rawText,
  }
}

function encryptTripPII(trip: Trip): Trip {
  return {
    ...trip,
    rawText: trip.rawText ? encryptWithPrefix(trip.rawText) : trip.rawText,
  }
}

function decrypt(ciphertext: string): string {
  if (!ciphertext) return ciphertext

  try {
    const key = getMasterKey()
    const data = Buffer.from(ciphertext, "base64")

    const iv = data.subarray(0, IV_LENGTH)
    const authTag = data.subarray(IV_LENGTH, IV_LENGTH + TAG_LENGTH)
    const encrypted = data.subarray(IV_LENGTH + TAG_LENGTH)

    const decipher = createDecipheriv(ALGORITHM, key, iv)
    decipher.setAuthTag(authTag)

    const decrypted = Buffer.concat([
      decipher.update(encrypted),
      decipher.final(),
    ])
    return decrypted.toString("utf8")
  } catch (err) {
    // If decryption fails, assume the value was stored unencrypted (backward compat)
    console.warn(
      "Decryption failed, returning original value:",
      err instanceof Error ? err.message : String(err)
    )
    return ciphertext
  }
}

function encodePrefs(prefs: UserPreferences): string {
  return encryptWithPrefix(JSON.stringify(prefs))
}
